  + '</td></tr></table><p style="margin:20px 0 0;font-size:11px;color:#bbb;">2026 Nome Magnetico - Studio MLK</p></td></tr></table></body></html>';

return [{ json: { to: email, subject: 'Recebemos sua mensagem - Nome Magnetico', html: html } }];

// TICKET REPLY: prepara para IA polish
var p = $json.payload || {};
var nome = (p.nome || p.firstName || 'Cliente').split(' ')[0];
var assunto = p.assunto || p.ticketSubject || 'Suporte';
var toEmail = p.email || '';
var mensagem = p.mensagem || '';

return [{ json: { toEmail: toEmail, nome: nome, assunto: assunto, mensagemOriginal: mensagem } }];

// Extrai texto polido e monta email de resposta
