var html = '<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"/></head><body style="margin:0;padding:0;background:#f0f0f0;font-family:Arial,Helvetica,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f0f0;padding:40px 16px;"><tr><td align="center"><table width="560" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,0.08);"><tr><td style="padding:32px 36px;">'
  + '<div style="font-size:15px;color:#333;line-height:1.8;">' + textoHtml + '</div>'
  + '<p style="margin:24px 0 8px;font-size:13px;color:#aaa;">Em caso de duvidas, <a href="https://nomemagnetico.com.br/app/suporte" style="color:#b8942a;text-decoration:none;">abra um novo ticket</a>.</p>'
  + sig
  + '</td></tr></table><p style="margin:20px 0 0;font-size:11px;color:#bbb;">2026 Nome Magnetico - Studio MLK</p></td></tr></table></body></html>';

return [{ json: { to: email, subject: 'Re: ' + assunto + ' - Nome Magnetico', html: html } }];

